mapper.select:
SELECT d.id, d.department_id, d.name, d.description, d.alias, d.location, d.treatment, d.symptoms, d.treatment_period, d.cure_rate, d.examinations, d.follow_count, d.create_time, dept.name AS department_name FROM t_disease d LEFT JOIN t_department dept ON d.department_id = dept.id
AND d.department_id = #{departmentId}
ORDER BY d.follow_count DESC, d.id ASC
